import React, { useState } from 'react';
import TodoItem from '../TodoItem';
import TODOS from '../../mock/todos';
import './style.css';

export default function ToDoPage() {
  const [todos, setTodos] = useState(TODOS);
  const [newTodo, setNewTodo] = useState('');

  const handleAddTodo = () => {
    const trimmed = newTodo.trim();

    if (!trimmed) {
      return;
    }

    setTodos((prev) => [
      ...prev,
      { id: Date.now(), title: trimmed, completed: false },
    ]);
    setNewTodo('');
  };

  const handleToggleTodo = (id) => {
    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id ? { ...todo, completed: !todo.completed } : todo
      )
    );
  };

  return (
    <main className="todo-page">
      <section className="todo-panel">
        <p className="todo-kicker">To Do</p>
        <h1>To Do List</h1>
        <p className="todo-text">Add simple tasks and click an item to open its details page.</p>

        <div className="todo-form">
          <input
            type="text"
            value={newTodo}
            onChange={(event) => setNewTodo(event.target.value)}
            placeholder="Write a new task..."
          />
          <button type="button" className="ui-button ui-button--primary" onClick={handleAddTodo}>Add Todo</button>
        </div>

        <div className="todo-grid">
          {todos.map((todo) => (
            <TodoItem
              key={todo.id}
              id={todo.id}
              title={todo.title}
              completed={todo.completed}
              todo={todo}
              onClick={() => handleToggleTodo(todo.id)}
            />
          ))}
        </div>
      </section>
    </main>
  );
}
